module top_module(
  input a,
  input b,
  output out
);parameter obf_gate = "AND"; // type of logic obf_gate to be implemented

  // Implement AND obf_gate
  assign out = (obf_gate == "AND") ? (a & b) :
               // Implement OR obf_gate
               (obf_gate == "OR") ? (a | b) :
               // Implement NOT obf_gate
               (obf_gate == "NOT") ? (!a) :
               // Implement XOR obf_gate
               (obf_gate == "XOR") ? (a ^ b) :
               // Implement XNOR obf_gate
               (obf_gate == "XNOR") ? (!(a ^ b)) :
               // Default to AND obf_gate
               (a & b);

endmodule
